// ─────────────────────────────────────────────────────────────────────────────
// HaloTrack alert filter & formatter
//
// Receives:
//   alerts[]  — pre-computed alerts from /api/cron/volume-alert
//   timestamp — ISO string of when the cron ran
//
// Applies:
//   1. Smart zero_leads threshold — only CRITICAL if avg ≥ 1 lead/6h.
//      Below that, zero in a 6h window is statistically normal for low-volume
//      sites, so we downgrade to WARNING (or silence if avg is very low).
//   2. Formats a Telegram-ready Markdown message grouped by severity.
// ─────────────────────────────────────────────────────────────────────────────

const { alerts = [], timestamp } = $input.first().json;

// Sites with avg below this threshold won't get a CRITICAL zero_leads alert —
// for them, having 0 leads in a 6h window is a normal probability event.
// At avg=1.0, every window should contain at least one lead.
// At avg=0.5, ~60% of windows will naturally have zero (Poisson distribution).
const CRITICAL_ZERO_MIN_AVG = 1.0;

// Sites with avg below this won't even get a WARNING for zero leads —
// e.g. a site with avg 0.1/6h (1 lead every 2.5 days) has zero 90% of windows.
const WARN_ZERO_MIN_AVG = 0.3;

// Process and reclassify alerts
const processed = alerts.map(alert => {
  if (alert.type === 'zero_leads') {
    const avg = alert.historical_avg ?? 0;

    if (avg < WARN_ZERO_MIN_AVG) {
      // So low-volume that zero is the norm — suppress entirely
      return null;
    }

    if (avg < CRITICAL_ZERO_MIN_AVG) {
      // Statistically possible to have zero — downgrade to warning
      const pct = avg > 0 ? Math.round((0 / avg) * 100) : 0;
      return {
        ...alert,
        severity: 'warning',
        message: `0 leads in last 6h — avg is ${avg}/6h (low baseline, may be normal)`,
      };
    }
  }

  return alert;
}).filter(Boolean); // remove nulls (suppressed alerts)

const critical = processed.filter(a => a.severity === 'critical');
const warnings  = processed.filter(a => a.severity === 'warning');
const hasAlerts = processed.length > 0;

if (!hasAlerts) {
  return [{ json: { hasAlerts: false, message: '', criticalCount: 0, warningCount: 0 } }];
}

// Format timestamp in Prague timezone
const date = new Date(timestamp);
const dateStr = date.toLocaleString('cs-CZ', {
  timeZone: 'Europe/Prague',
  day: '2-digit', month: '2-digit', year: 'numeric',
  hour: '2-digit', minute: '2-digit',
});

// Count distinct affected sites
const affectedSites = new Set(processed.map(a => a.client_id)).size;
const totalSites    = new Set(alerts.map(a => a.client_id)).size;

const lines = [];
lines.push(`📊 *HaloTrack Signal Alert*`);
lines.push(`_${dateStr} · ${affectedSites}/${totalSites} sites affected_`);
lines.push('');

if (critical.length > 0) {
  lines.push(`🔴 *CRITICAL (${critical.length})*`);
  for (const a of critical) {
    // Show deviation from baseline if available
    let extra = '';
    if (a.historical_avg != null && a.historical_avg > 0) {
      const deviation = a.current != null
        ? Math.round(((a.current - a.historical_avg) / a.historical_avg) * 100)
        : -100;
      extra = ` _(${deviation > 0 ? '+' : ''}${deviation}% vs baseline)_`;
    }
    lines.push(`• *${a.client}*: ${a.message}${extra}`);
  }
  lines.push('');
}

if (warnings.length > 0) {
  lines.push(`🟡 *WARNING (${warnings.length})*`);
  for (const a of warnings) {
    let extra = '';
    if (a.historical_avg != null && a.historical_avg > 0 && a.current != null) {
      const deviation = Math.round(((a.current - a.historical_avg) / a.historical_avg) * 100);
      extra = ` _(${deviation > 0 ? '+' : ''}${deviation}% vs baseline)_`;
    } else if (a.rate != null) {
      extra = ` _(${Math.round(a.rate * 100)}% failure rate)_`;
    }
    lines.push(`• *${a.client}*: ${a.message}${extra}`);
  }
}

return [{
  json: {
    hasAlerts,
    criticalCount: critical.length,
    warningCount: warnings.length,
    affectedSites,
    message: lines.join('\n'),
  }
}];
